var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"야, 스승.","JPN":"ねえ、師匠。","ENG":"Hey, Master.","TWN":"喂，師父。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"발키리가 된다는 건, 어떤 의미냐?","JPN":"ヴァルキリーになるって、どういう意味？","ENG":"So what does it mean to become a Valkyrie?","TWN":"成為女武神……到底代表什麼？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"넌 그런 것도 모르면서 발키리가 되겠다고 했나?","JPN":"お前はそれも知らずにヴァルキリーになると決めたのか？","ENG":"You said you wanted to become a Valkyrie without even knowing that?","TWN":"你連這個都不知道，就說要成為女武神嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"강한 녀석과 싸울 수만 있으면 돼.","JPN":"強いやつと戦えるならそれでいい。","ENG":"As long as I get to fight someone strong, that's enough.","TWN":"我只要能跟強者戰鬥就夠了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"너도 그런 내 성미를 이해하는 줄 알았는데, 아니었어?","JPN":"師匠も私のそういうところを気に入ってると思ったんだけど？","ENG":"I figured that was what you liked about me.","TWN":"我還以為你就是喜歡我這一點呢？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"세계는 빛으로 창조 되고 어둠에 삼켜져 종말을 맞는다.","JPN":"世界は光で創造され、闇に呑まれて終末を迎える。","ENG":"The world is created by light and meets its end when it is swallowed by darkness.","TWN":"世界由光所創造，最終會被黑暗吞噬而迎來末日。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"그러니 어둠을 몰아내면 세계는 영원히 존속할 수 있지.","JPN":"ゆえに闇を払えば、世界は永遠に存続できる。","ENG":"So if we drive away the darkness, the world can endure forever.","TWN":"所以只要驅逐黑暗，世界就能永遠存續。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"발키리가 된다는 건- 종말을 가져오는 어둠에 맞서는 영원한 빛이 된다는 뜻이다.","JPN":"ヴァルキリーになるということは、終末をもたらす闇に立ち向かう、永遠の光になるという意味だ。","ENG":"To become a Valkyrie means becoming an eternal light that stands against the darkness that brings the end.","TWN":"成為女武神—就是成為對抗末日黑暗的永恆之光。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"흐음...","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"나쁘지 않네. 영원히 싸울 수 있다는 뜻이잖아?","JPN":"悪くないね。永遠に戦えるってことじゃん？","ENG":"Not bad. That means I get to keep fighting forever, right?","TWN":"還不錯嘛。意思就是能永遠戰鬥對吧？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"싸우는 것 말고, 지킨다는 것에 자부심을 가지도록.","JPN":"戦うことではなく、守るということに誇りを持て。","ENG":"Take pride not in fighting, but in protecting.","TWN":"你別只把重心放在戰鬥上，也試著為守護感到自豪。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"왜? 사람은 언젠가 죽어. 세계도 그 언젠가가 되면 끝나겠지.","JPN":"なんで？　人間はいつか死ぬし。世界も終わる時が来れば終わるんだよ。","ENG":"Why? People die someday. The world will end someday too.","TWN":"為什麼？人終究會死，世界總有一天也會終結。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"난 별로, 그런 걸 긍지까지 가져가면서 지키고 싶진 않아.","JPN":"私は別に、誇りを持ってまでそういうものを守りたいと思わないな。","ENG":"I don't care enough about something like that to take pride in protecting it.","TWN":"我可不想抱著什麼自豪感去守護那種東西。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"하아...","JPN":"はあ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"너 같은 녀석이 어쩌다 대적자로 선택 받은 건지 모르겠군.","JPN":"お前のようなやつがなぜ敵対者として選ばれたのか、理由が分からないな。","ENG":"I don't know how someone like you ended up being chosen as an Antagonist.","TWN":"真不知道你這種傢伙怎麼會被選為敵對者。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"그런 식으로 말하니까, 폭군이니 검은 역병의 원흉이니 같은 오해를 사는 거다.","JPN":"そういう言い方をするから、暴君だの黒い疫病の元凶だのと誤解されるんだ。","ENG":"Talking like that is exactly why people misunderstand you as a tyrant or the source of the Black Plague.","TWN":"就是因為你這樣講話，才會被誤會成暴君、黑色瘟疫的元兇。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"아하핫! 마음껏 오해하라고 해.","JPN":"あははっ！　好きなだけ誤解させときなって。","ENG":"Ahaha! Let them misunderstand me all they want.","TWN":"哈哈哈！那就讓他們誤會啊。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"녀석들이 그렇게 소문을 내준 덕에 세상 강자들이 전부 날 이겨먹겠다고 제 발로 찾아오잖아? 이보다 좋은 기회가 어딨겠어?","JPN":"そうやって噂を広めてくれたおかげで、世界中の強者が私に勝つために自分から来てくれるんだよ？　これ以上おいしいチャンスはなかなかないよ。","ENG":"Thanks to those rumors, every strong fighter in the world keeps showing up right at my doorstep to challenge me. What better opportunity could I ask for?","TWN":"多虧那些傳聞，世界各地的強者全都自己送上門來想打敗我，哪有比這更好的機會？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"정말이지. 성격 하나는 마왕보다 더 마왕스럽군.","JPN":"まったく。性格だけは魔王よりも魔王らしいな。","ENG":"Honestly. Your personality is more Demon Lord-like than an actual Demon Lord's.","TWN":"真是的，你這個性比魔王還像魔王。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"오히려 그 편이 낫지. 마음에도 없는 정의를 논할 바엔 마왕이 되는 거 말이야.","JPN":"かえってそのほうがましかも。心にもない正義を論ずるぐらいなら、魔王になったほうがいい。","ENG":"That's even better. If the alternative is pretending to care about justice I don't believe in, I'd rather become a Demon Lord.","TWN":"這樣反而更好。與其談論那些虛假的正義，不如乾脆當魔王。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"그렇게 되면, 너하고도 진심으로 겨뤄볼 수 있을 테고.","JPN":"そうしたら、師匠とも本気で戦えるだろうし。","ENG":"If that happens, I'd finally be able to fight you seriously too.","TWN":"這樣一來……也能和你痛痛快快打一場。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"...웃기지 마라.","JPN":"……ふざけるな。","ENG":"...Don't be ridiculous.","TWN":"……別開玩笑了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"넌 발키리가 될 거다. 마왕이 아니라.","JPN":"お前はヴァルキリーになる。魔王ではなく。","ENG":"You're going to become a Valkyrie. Not a Demon Lord.","TWN":"你會成為女武神，不是魔王。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"아하하, 왜? 마왕이 된 나랑 싸우면 질까 봐 무서워?","JPN":"あはは、何で？　魔王になった私と戦ったら負けそうで怖い？","ENG":"Ahaha, why? Afraid you'd lose if I became a Demon Lord?","TWN":"哈哈，怎麼了？你怕會打輸成為魔王的我嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"나와 한 맹세를 잊었나?","JPN":"私との誓いを忘れたか？","ENG":"Have you already forgotten the oath you made with me?","TWN":"你忘了和我立下的誓言嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"내가 대적자를 가르치는 건 마왕에 맞서기 위함이다. 마왕이 되기 위해서가 아니라!","JPN":"私が敵対者を育てるのは魔王に立ち向かうためだ。魔王にするためではない！","ENG":"I teach the Antagonist so she can stand against the Demon Lord. Not so she can become one!","TWN":"我教導敵對者是為了對抗魔王，不是讓你成為魔王！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"흥, 그깟 맹세 개나 주라지. 난 더 재미있는 쪽이 좋거든.","JPN":"ふん、そんな誓い、どうでもいいよ。私は面白ければ、そっちのほうがいい。","ENG":"Hmph, you can shove that oath. I prefer whichever path sounds more interesting.","TWN":"哼，誰要理那種誓言。我只選更有趣的那條路。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"하아.","JPN":"はあ。","ENG":"*Sigh*","TWN":"唉。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"시련?","JPN":"試練？","ENG":"A trial?","TWN":"試煉？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"그래. 발키리가 되는 마지막 시험으로서, 심연이 보낸 첫 번째 종말을 막는 거다.","JPN":"ああ。ヴァルキリーになる最後の試練。深淵が送り出した初めての終末を食い止めるんだ。","ENG":"Yes. As your final trial to become a Valkyrie, you must stop the first apocalypse sent by the Abyss.","TWN":"對。作為成為女武神的最後試煉，阻止深淵派來的第一個末日。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"이 세계에 강림한 마왕을 상대하는 거지.","JPN":"この世界に降臨した魔王と戦うことになる。","ENG":"You'll be facing the Demon Lord who has descended upon this world.","TWN":"也就是對抗降臨於這個世界的魔王。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"마왕을 죽인다라. 재밌겠네.","JPN":"魔王を殺すのか。面白そう。","ENG":"Killing a Demon Lord, huh. Sounds fun.","TWN":"殺掉魔王啊……挺有意思的。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};